+    let raw = Box::into_raw(fa);
+    let p = file_actions as *mut u8;
+    unsafe {
+        *(p.add(FA_MAGIC_OFF) as *mut u64) = SPAWN_FA_MAGIC;
+        *(p.add(FA_PTR_OFF) as *mut *mut SpawnFileActions) = raw;
+    }
+    0
